#include <bits/stdc++.h>
using namespace std;
struct Node{
    Node *left,*right,*father;
    int data,Size,rank;
};
Node *root;
void solve1(int x){
	Node *p=root;
	int ans=0;
	while(p!=NULL){
		if(p->data==x){
			ans+=p->Size-(p->right==NULL?0:p->right->Size)-1;
			break;
		}else if(p->data<x)
			ans+=p->Size-(p->right==NULL? 0:p->right->Size),p=p->right;
		else
			p=p->left;
	}
	printf("%d\n",ans+1);
}
void solve2(int x){
	Node *p=root;
	while(p!=NULL){
		if(p->father==NULL)
			p->rank=(p->left==NULL?0:p->left->Size)+1;
		else if(p->father->data > p->data)
			p->rank=p->father->rank-(p->right==NULL? 0:p->right->Size)-1;
		else
			p->rank=p->father->rank+(p->left==NULL? 0:p->left->Size)+1;
		if(p->rank==x){
			printf("%d\n",p->data);
			return;
		}else if(p->rank<x)
			p=p->right;
		else
			p=p->left;
	}
}
void solve3(int x){
	int ans=-2147483647;
	Node *p=root;
	while(p!=NULL){
		if(p->data<x)
			ans=p->data,p=p->right;
		else
			p=p->left;
	}
	printf("%d\n",ans);
}
void solve4(int x){
	int ans=2147483647;
	Node *p=root;
	while(p!=NULL){
		if(p->data>x)
			ans=p->data,p=p->left;
		else
			p=p->right;
	}
	printf("%d\n",ans);
}
void solve5(int x){
	if(root==NULL){
		root=new Node;
		root->data=x;
		root->left=root->right=root->father=NULL;
		root->Size=1;
		return;
	}
	Node *p=root,*last;
	while(p!=NULL){
		p->Size++;
		last=p;
		if(p->data<x)
			p=p->right;
		else
			p=p->left;
	}
	p=new Node;
	p->data=x;
	p->Size=1;
	p->father=last;
	p->left=p->right=NULL;
	if(last->data<x)
		last->right=p;
	else
		last->left=p;
}
int main(){
	int q,op,x;
    scanf("%d",&q);
    root=NULL;
    while(q--){
        scanf("%d%d",&op,&x);
        if(op==1)
            solve1(x);
        else if(op==2)
            solve2(x);
        else if(op==3)
            solve3(x);
        else if(op==4)
            solve4(x);
        else if(op==5)
            solve5(x);
    }
    return 0;
}
